const express = require('express');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const db = {
  players: new Map(),
  levels: new Map(),
  rewards: new Map()
};

function now() {
  return Date.now();
}

function randomId(prefix) {
  return `${prefix}_${crypto.randomBytes(8).toString('hex')}`;
}

function getOrCreatePlayer(playerId) {
  if (!db.players.has(playerId)) {
    db.players.set(playerId, {
      id: playerId,
      coins: 0,
      gems: 0,
      completedLevels: {},
      claimedRewards: {},
      createdAt: now(),
      updatedAt: now()
    });
  }
  return db.players.get(playerId);
}

function getLevelConfig(levelId) {
  if (!db.levels.has(levelId)) {
    const numeric = Number(levelId) || 1;
    db.levels.set(levelId, {
      id: levelId,
      baseCoins: 50 + numeric * 10,
      baseGems: Math.max(1, Math.floor(numeric / 5)),
      targetTimeSeconds: Math.max(20, 180 - numeric * 3),
      targetScore: 1000 + numeric * 200
    });
  }
  return db.levels.get(levelId);
}

function calculateReward(levelConfig, score, timeSeconds) {
  let coins = levelConfig.baseCoins;
  let gems = levelConfig.baseGems;

  if (score >= levelConfig.targetScore) {
    coins += 25;
    gems += 1;
  }

  if (score >= levelConfig.targetScore * 1.5) {
    coins += 50;
    gems += 2;
  }

  if (timeSeconds <= levelConfig.targetTimeSeconds) {
    coins += 20;
  }

  if (timeSeconds <= Math.floor(levelConfig.targetTimeSeconds * 0.75)) {
    coins += 30;
    gems += 1;
  }

  return {
    coins,
    gems
  };
}

app.post('/levels/complete', (req, res) => {
  const { playerId, levelId, score, timeSeconds } = req.body;

  if (!playerId || !levelId || typeof score !== 'number' || typeof timeSeconds !== 'number') {
    return res.status(400).json({
      error: 'playerId, levelId, score, and timeSeconds are required'
    });
  }

  if (score < 0 || timeSeconds <= 0) {
    return res.status(400).json({
      error: 'score must be >= 0 and timeSeconds must be > 0'
    });
  }

  const player = getOrCreatePlayer(String(playerId));
  const level = getLevelConfig(String(levelId));
  const reward = calculateReward(level, score, timeSeconds);

  const completionId = randomId('cmp');
  const completion = {
    id: completionId,
    playerId: player.id,
    levelId: level.id,
    score,
    timeSeconds,
    reward,
    claimed: false,
    completedAt: now()
  };

  if (!player.completedLevels[level.id]) {
    player.completedLevels[level.id] = [];
  }

  player.completedLevels[level.id].push(completion);
  db.rewards.set(completionId, completion);
  player.updatedAt = now();

  res.json({
    success: true,
    completionId,
    rewardPreview: reward
  });
});

app.post('/rewards/claim', (req, res) => {
  const { playerId, completionId } = req.body;

  if (!playerId || !completionId) {
    return res.status(400).json({
      error: 'playerId and completionId are required'
    });
  }

  const player = db.players.get(String(playerId));
  if (!player) {
    return res.status(404).json({
      error: 'player not found'
    });
  }

  const completion = db.rewards.get(String(completionId));
  if (!completion || completion.playerId !== player.id) {
    return res.status(404).json({
      error: 'completion not found'
    });
  }

  if (completion.claimed) {
    return res.status(409).json({
      error: 'reward already claimed'
    });
  }

  completion.claimed = true;
  completion.claimedAt = now();
  player.coins += completion.reward.coins;
  player.gems += completion.reward.gems;
  player.claimedRewards[completion.id] = true;
  player.updatedAt = now();

  res.json({
    success: true,
    claimedReward: completion.reward,
    balances: {
      coins: player.coins,
      gems: player.gems
    }
  });
});

app.get('/players/:playerId', (req, res) => {
  const player = db.players.get(String(req.params.playerId));
  if (!player) {
    return res.status(404).json({ error: 'player not found' });
  }

  res.json({
    id: player.id,
    balances: {
      coins: player.coins,
      gems: player.gems
    },
    completedLevels: player.completedLevels,
    createdAt: player.createdAt,
    updatedAt: player.updatedAt
  });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  console.log(`Game API listening on port ${port}`);
});